//! # Sweep Service — Systematic Frequency Coverage Engine
//!
//! Separate process providing deterministic complete frequency sweep coverage
//! using gnosis-frf for parallel processing. Communicates with aeon-monitor
//! via IPC for frame ingestion and result distribution.

use distributed_inference::pleromatic_frame::PleromaticFrame;
use std::env;

// --- Service Identification ---

#[derive(Debug, Clone)]
pub struct ServiceId {
    pub monitor_id: String,
    pub hub_id: String,
    pub service_type: String,
}

impl ServiceId {
    fn new(monitor_id: &str, hub_id: &str, service_type: &str) -> Self {
        Self {
            monitor_id: monitor_id.to_string(),
            hub_id: hub_id.to_string(),
            service_type: service_type.to_string(),
        }
    }

    fn socket_path(&self) -> String {
        format!(
            "/tmp/sweep-service-{}-{}.sock",
            self.monitor_id, self.hub_id
        )
    }

    fn from_env() -> Self {
        let monitor_id = env::var("AEON_MONITOR_ID").unwrap_or_else(|_| "default".to_string());
        let hub_id = env::var("AEON_HUB_ID").unwrap_or_else(|_| "hub-0".to_string());
        Self::new(&monitor_id, &hub_id, "sweep")
    }
}
use gnosis_frf::prelude::*;
use serde::{Deserialize, Serialize};
use std::collections::VecDeque;
use std::io::{self, Read, Write};
use std::os::unix::net::{UnixListener, UnixStream};
use std::path::Path;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, SystemTime, UNIX_EPOCH};

// --- Frequency Grid Structure ---

#[derive(Debug, Clone)]
pub struct FrequencyBin {
    pub center_hz: u64,
    pub bandwidth_hz: u64,
    pub magnitude_history: VecDeque<f32>,
    pub last_analyzed: Option<SystemTime>,
    pub detection_count: u32,
    pub max_magnitude: f32,
}

impl FrequencyBin {
    fn new(center_hz: u64, bandwidth_hz: u64) -> Self {
        Self {
            center_hz,
            bandwidth_hz,
            magnitude_history: VecDeque::with_capacity(60), // 60-second history
            last_analyzed: None,
            detection_count: 0,
            max_magnitude: 0.0,
        }
    }

    fn ingest_magnitude(&mut self, magnitude: f32) {
        self.magnitude_history.push_back(magnitude);
        if self.magnitude_history.len() > 60 {
            self.magnitude_history.pop_front();
        }
        self.last_analyzed = Some(SystemTime::now());
        self.detection_count += 1;
        self.max_magnitude = self.max_magnitude.max(magnitude);
    }

    fn get_current_magnitude(&self) -> f32 {
        self.magnitude_history.back().copied().unwrap_or(0.0)
    }

    fn is_active(&self, threshold: f32) -> bool {
        self.get_current_magnitude() > threshold
    }
}

#[derive(Debug)]
pub struct FrequencyGrid {
    bins: Vec<FrequencyBin>,
    coverage_map: bitvec::vec::BitVec,
    temporal_window: VecDeque<TemporalSnapshot>,
    sweep_interval_ms: u64,
    last_sweep_time: Option<SystemTime>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TemporalSnapshot {
    pub timestamp_ms: u64,
    pub active_bins: Vec<usize>,
    pub coverage_percentage: f32,
    pub total_energy: f32,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SweepResult {
    pub timestamp_ms: u64,
    pub coverage_percentage: f32,
    pub active_bins: usize,
    pub total_energy: f32,
    pub sweep_duration_ms: u64,
    pub frequency_peaks: Vec<FrequencyPeak>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FrequencyPeak {
    pub bin_index: usize,
    pub center_hz: u64,
    pub magnitude: f32,
    pub bandwidth_hz: u64,
}

impl FrequencyGrid {
    fn new(start_hz: u64, end_hz: u64, bin_width_hz: u64) -> Self {
        let num_bins = ((end_hz - start_hz) / bin_width_hz) as usize;
        let mut bins = Vec::with_capacity(num_bins);

        for i in 0..num_bins {
            let center_hz = start_hz + (i as u64 * bin_width_hz) + bin_width_hz / 2;
            bins.push(FrequencyBin::new(center_hz, bin_width_hz));
        }

        Self {
            bins,
            coverage_map: bitvec::vec::BitVec::repeat(false, num_bins),
            temporal_window: VecDeque::with_capacity(60),
            sweep_interval_ms: 10000, // 10 seconds default
            last_sweep_time: None,
        }
    }

    fn ingest_frame(&mut self, frame: &PleromaticFrame) {
        if !frame.is_spectrogram_waterfall() {
            return;
        }

        // Extract frequency data from spectrogram frame
        let spec_width = frame
            .attributes
            .get("spec_width")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or(512);

        let center_hz = frame
            .attributes
            .get("rf_center_hz")
            .and_then(|h| h.parse::<u64>().ok())
            .unwrap_or(0);

        // Process the newest row (most recent spectrum data)
        if frame.data.len() >= spec_width {
            let newest_row = &frame.data[frame.data.len() - spec_width..];
            let bin_width = 256000.0 / spec_width as f32; // Assuming 256kHz span

            for (x, &val) in newest_row.iter().enumerate() {
                let magnitude = val as f32 / 255.0;
                let event_freq =
                    center_hz as f32 + (x as f32 - (spec_width as f32 / 2.0)) * bin_width;

                // Find corresponding bin
                if let Some(bin_index) = self.find_bin_for_frequency(event_freq as u64) {
                    self.bins[bin_index].ingest_magnitude(magnitude);
                    self.coverage_map.set(bin_index, true);
                }
            }
        }
    }

    fn find_bin_for_frequency(&self, freq_hz: u64) -> Option<usize> {
        if self.bins.is_empty() {
            return None;
        }

        let first_bin_center = self.bins[0].center_hz;
        let bin_width = self.bins[0].bandwidth_hz;

        if freq_hz < first_bin_center - bin_width / 2
            || (!self.bins.is_empty()
                && freq_hz > self.bins.last().unwrap().center_hz + bin_width / 2)
        {
            return None;
        }

        let index = ((freq_hz - first_bin_center) / bin_width) as usize;
        if index < self.bins.len() {
            Some(index)
        } else {
            None
        }
    }

    fn systematic_sweep(&mut self) -> SweepResult {
        let start_time = SystemTime::now();
        let timestamp_ms = start_time.duration_since(UNIX_EPOCH).unwrap().as_millis() as u64;

        // Use gnosis-frf for deterministic parallel processing
        let sweep_results: Vec<SweepBin> = (0..self.bins.len())
            .into_par_iter() // gnosis-frf parallel iterator
            .map(|i| self.analyze_bin_deterministic(i))
            .collect();

        // For now, we'll skip the fold operation and just use the results directly
        // The fold operation can be added later with proper trait imports
        let _combined_result = sweep_results
            .iter()
            .fold(SweepBin::new(), |acc, bin| acc.accumulate(bin.clone()));

        // Create temporal snapshot
        let active_bins: Vec<usize> = self
            .bins
            .iter()
            .enumerate()
            .filter(|(_, bin)| bin.is_active(0.1)) // 10% magnitude threshold
            .map(|(i, _)| i)
            .collect();

        let coverage_percentage =
            (self.coverage_map.count_ones() as f32 / self.bins.len() as f32) * 100.0;
        let total_energy = self
            .bins
            .iter()
            .map(|bin| bin.get_current_magnitude())
            .sum();

        let snapshot = TemporalSnapshot {
            timestamp_ms,
            active_bins: active_bins.clone(),
            coverage_percentage,
            total_energy,
        };

        self.temporal_window.push_back(snapshot);
        if self.temporal_window.len() > 60 {
            self.temporal_window.pop_front();
        }

        // Find frequency peaks
        let frequency_peaks: Vec<FrequencyPeak> = active_bins
            .iter()
            .map(|&i| {
                let bin = &self.bins[i];
                FrequencyPeak {
                    bin_index: i,
                    center_hz: bin.center_hz,
                    magnitude: bin.get_current_magnitude(),
                    bandwidth_hz: bin.bandwidth_hz,
                }
            })
            .collect();

        let sweep_duration_ms = start_time.elapsed().unwrap().as_millis() as u64;
        self.last_sweep_time = Some(start_time);

        SweepResult {
            timestamp_ms,
            coverage_percentage,
            active_bins: active_bins.len(),
            total_energy,
            sweep_duration_ms,
            frequency_peaks,
        }
    }

    fn analyze_bin_deterministic(&self, bin_index: usize) -> SweepBin {
        let bin = &self.bins[bin_index];
        let current_magnitude = bin.get_current_magnitude();
        let is_active = bin.is_active(0.1);
        let trend = self.calculate_trend(bin_index);

        SweepBin {
            _bin_index: bin_index,
            _center_hz: bin.center_hz,
            magnitude: current_magnitude,
            _is_active: is_active,
            _trend: trend,
            _detection_count: bin.detection_count,
        }
    }

    fn calculate_trend(&self, bin_index: usize) -> f32 {
        let bin = &self.bins[bin_index];
        let history = &bin.magnitude_history;

        if history.len() < 2 {
            return 0.0;
        }

        // Simple linear trend calculation
        let n = history.len() as f32;
        let sum_y: f32 = history.iter().sum();
        let sum_xy: f32 = history.iter().enumerate().map(|(i, &y)| i as f32 * y).sum();
        let sum_x = (0..history.len()).sum::<usize>() as f32;
        let sum_x2 = (0..history.len()).map(|i| i * i).sum::<usize>() as f32;

        
        (n * sum_xy - sum_x * sum_y) / (n * sum_x2 - sum_x * sum_x)
    }

    fn should_sweep(&self) -> bool {
        match self.last_sweep_time {
            None => true,
            Some(last_time) => {
                let elapsed = last_time.elapsed().unwrap().as_millis() as u64;
                elapsed >= self.sweep_interval_ms
            }
        }
    }
}

#[derive(Debug, Clone)]
struct SweepBin {
    _bin_index: usize,
    _center_hz: u64,
    magnitude: f32,
    _is_active: bool,
    _trend: f32,
    _detection_count: u32,
}

impl SweepBin {
    fn new() -> Self {
        Self {
            _bin_index: 0,
            _center_hz: 0,
            magnitude: 0.0,
            _is_active: false,
            _trend: 0.0,
            _detection_count: 0,
        }
    }

    fn accumulate(self, other: SweepBin) -> Self {
        // For folding, we'll keep the higher magnitude bin
        if other.magnitude > self.magnitude {
            other
        } else {
            self
        }
    }
}

// --- IPC Protocol ---

#[derive(Debug, Serialize, Deserialize)]
pub enum IpcMessage {
    Frame(PleromaticFrame),
    SweepRequest,
    SweepResult(SweepResult),
    Ping,
    Pong,
}

// --- Main Service ---

struct SweepService {
    service_id: ServiceId,
    frequency_grid: FrequencyGrid,
    ipc_listener: UnixListener,
}

impl SweepService {
    fn new(service_id: ServiceId) -> io::Result<Self> {
        let socket_path = service_id.socket_path();

        // Remove existing socket file if it exists
        if Path::new(&socket_path).exists() {
            std::fs::remove_file(&socket_path)?;
        }

        let ipc_listener = UnixListener::bind(&socket_path)?;

        // Initialize frequency grid (0 Hz to 2 GHz, 1kHz bins)
        let frequency_grid = FrequencyGrid::new(0, 2_000_000_000, 1_000);

        Ok(Self {
            service_id,
            frequency_grid,
            ipc_listener,
        })
    }

    fn run(&mut self) -> io::Result<()> {
        println!("[SWEEP-SERVICE] Started systematic sweep engine");
        println!(
            "[SWEEP-SERVICE] Service ID: {}-{}",
            self.service_id.monitor_id, self.service_id.hub_id
        );
        println!(
            "[SWEEP-SERVICE] Frequency grid: {} bins (1kHz resolution)",
            self.frequency_grid.bins.len()
        );
        println!("[SWEEP-SERVICE] Socket: {}", self.service_id.socket_path());
        println!("[SWEEP-SERVICE] Listening for IPC connections...");

        // Move frequency grid into Arc for sharing between threads
        // Create a new empty grid to replace the old one
        let empty_grid = FrequencyGrid::new(0, 2_000_000_000, 1_000);
        let grid_shared = Arc::new(Mutex::new(std::mem::replace(
            &mut self.frequency_grid,
            empty_grid,
        )));
        let grid_sweep = Arc::clone(&grid_shared);

        // Background sweep thread
        thread::spawn(move || loop {
            thread::sleep(Duration::from_millis(100));
            let mut grid = grid_sweep.lock().unwrap();
            if grid.should_sweep() {
                let result = grid.systematic_sweep();
                println!("[SWEEP-SERVICE] Systematic sweep completed: {:.1}% coverage, {} active bins, {}ms",
                        result.coverage_percentage, result.active_bins, result.sweep_duration_ms);
            }
        });

        // Main IPC loop
        let listener = std::mem::replace(
            &mut self.ipc_listener,
            UnixListener::bind("/tmp/dummy.sock").unwrap(),
        );
        for stream in listener.incoming() {
            match stream {
                Ok(stream) => {
                    if let Err(e) = self.handle_client(stream, &grid_shared) {
                        eprintln!("[SWEEP-SERVICE] Error handling client: {}", e);
                    }
                }
                Err(e) => {
                    eprintln!("[SWEEP-SERVICE] Connection error: {}", e);
                }
            }
        }

        Ok(())
    }

    fn handle_client(
        &mut self,
        mut stream: UnixStream,
        grid_shared: &Arc<Mutex<FrequencyGrid>>,
    ) -> io::Result<()> {
        println!("[SWEEP-SERVICE] Client connected");

        loop {
            // Read message length first (4 bytes)
            let mut len_bytes = [0u8; 4];
            if stream.read_exact(&mut len_bytes).is_err() {
                break; // Client disconnected
            }

            let len = u32::from_le_bytes(len_bytes) as usize;
            if len > 1_000_000 {
                // 1MB limit
                eprintln!("[SWEEP-SERVICE] Message too large: {} bytes", len);
                break;
            }

            // Read message
            let mut buffer = vec![0u8; len];
            if stream.read_exact(&mut buffer).is_err() {
                break;
            }

            // Deserialize message
            let message: IpcMessage = bincode::deserialize(&buffer)
                .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;

            match message {
                IpcMessage::Frame(frame) => {
                    let mut grid = grid_shared.lock().unwrap();
                    grid.ingest_frame(&frame);
                }
                IpcMessage::SweepRequest => {
                    let mut grid = grid_shared.lock().unwrap();
                    let result = grid.systematic_sweep();
                    let response = IpcMessage::SweepResult(result);
                    let response_data = bincode::serialize(&response).unwrap();
                    let response_len = (response_data.len() as u32).to_le_bytes();

                    stream.write_all(&response_len)?;
                    stream.write_all(&response_data)?;
                }
                IpcMessage::Ping => {
                    let response = IpcMessage::Pong;
                    let response_data = bincode::serialize(&response).unwrap();
                    let response_len = (response_data.len() as u32).to_le_bytes();

                    stream.write_all(&response_len)?;
                    stream.write_all(&response_data)?;
                }
                _ => {
                    eprintln!("[SWEEP-SERVICE] Unexpected message type");
                }
            }
        }

        println!("[SWEEP-SERVICE] Client disconnected");
        Ok(())
    }
}

// --- Main Function ---

fn main() -> io::Result<()> {
    let service_id = ServiceId::from_env();

    println!("[SWEEP-SERVICE] Starting systematic sweep service...");
    println!("[SWEEP-SERVICE] Monitor ID: {}", service_id.monitor_id);
    println!("[SWEEP-SERVICE] Hub ID: {}", service_id.hub_id);
    println!("[SWEEP-SERVICE] Socket path: {}", service_id.socket_path());

    let mut service = SweepService::new(service_id)?;
    service.run()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_frequency_grid_creation() {
        let grid = FrequencyGrid::new(0, 1_000_000, 1_000);
        assert_eq!(grid.bins.len(), 1000);
        assert_eq!(grid.bins[0].center_hz, 500);
        assert_eq!(grid.bins[999].center_hz, 999_500);
    }

    #[test]
    fn test_frequency_bin_operations() {
        let mut bin = FrequencyBin::new(100_000_000, 1_000);

        assert_eq!(bin.get_current_magnitude(), 0.0);
        assert!(!bin.is_active(0.1));

        bin.ingest_magnitude(0.5);
        assert_eq!(bin.get_current_magnitude(), 0.5);
        assert!(bin.is_active(0.1));
        assert_eq!(bin.detection_count, 1);
    }

    #[test]
    fn test_sweep_bin_accumulation() {
        let bin1 = SweepBin {
            _bin_index: 0,
            _center_hz: 100_000,
            magnitude: 0.3,
            _is_active: true,
            _trend: 0.1,
            _detection_count: 5,
        };

        let bin2 = SweepBin {
            _bin_index: 1,
            _center_hz: 101_000,
            magnitude: 0.7,
            _is_active: true,
            _trend: -0.2,
            _detection_count: 3,
        };

        let accumulated = bin1.accumulate(bin2);
        assert_eq!(accumulated.magnitude, 0.7); // Higher magnitude wins
    }

    #[test]
    fn test_ipc_message_serialization() {
        let message = IpcMessage::Ping;
        let serialized = bincode::serialize(&message).unwrap();
        let deserialized: IpcMessage = bincode::deserialize(&serialized).unwrap();

        match deserialized {
            IpcMessage::Ping => {} // Expected
            _ => panic!("Deserialized message mismatch"),
        }
    }
}
